use aiken/math
use aiken/transaction.{OutputReference, Transaction}

pub type PaymentDatum {
  amount: Int,
  fee: Int,
  min_net: Int,
}

validator bounded_payment {
  spend(
    datum: Option<PaymentDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let effective_fee = math.max(d.fee, 0)
        let net = d.amount - effective_fee
        net >= d.min_net
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/math
use aiken/collection/list

pub type ShiftDatum {
  bits: Int,
  min_value: Int,
}

validator bitshift_validator {
  spend(
    datum: Option<ShiftDatum>,
    _redeemer: Data,
    _ref: aiken/primitive/bytearray.ByteArray,
    _self: aiken/transaction.Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let shifted = math.pow2(d.bits)
        shifted >= d.min_value
      }
    }
  }
}

