use aiken/math/rational
use aiken/transaction.{OutputReference, Transaction}

pub type CeilDatum {
  amount: Int,
  fee_bps: Int,
  max_fee: Int,
}

validator ceil_fee_validator {
  spend(datum: Option<CeilDatum>, _redeemer: Data, _ref: OutputReference, _self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        expect Some(rate) = rational.new(d.fee_bps, 10000)
        let fee = rational.ceil(rational.mul(rate, rational.from_int(d.amount)))
        fee <= d.max_fee
      }
    }
  }
}

use aiken/math/rational
use cardano/transaction.{OutputReference, Transaction}

pub type RatioDatum {
  num: Int,
  den: Int,
}

validator ratio_above_half {
  spend(
    datum: Option<RatioDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when rational.new(d.num, d.den) is {
          None -> False
          Some(r) ->
            rational.compare_with(
              r,
              fn(a, b) { a * 2 > b },
              rational.new(1, 2) |> option.or_else(rational.zero),
            )
        }
    }
  }

  else(_) {
    fail
  }
}
